import java.io.*;

public class SecureCommandExecutionExample {

    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
        System.out.print("Enter a command to execute: ");
        String userInput = reader.readLine();

        // Sanitize user input to prevent command injection
        String sanitizedInput = userInput.replaceAll("[^a-zA-Z0-9]", ""); // Allow only alphanumeric characters

        // Execute the sanitized command using ProcessBuilder
        ProcessBuilder processBuilder = new ProcessBuilder("echo", sanitizedInput);
        Process process = processBuilder.start();

        // Read and display the output of the executed command
        BufferedReader outputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
        String line;
        while ((line = outputReader.readLine()) != null) {
            System.out.println(line);
        }
    }
}

